<script>
    import { askConfigured, askStream } from '../utils/askSite';
    import {
        citedSourcesFromAnswer,
        cleanAskContextText,
        retrieveAskContexts,
        stripAnswerCitations,
    } from '../utils/askRetrieval';

    export default {
        name: 'IndexPage',
        data() {
            return {
                scriptModule: null,
                askText: '',
                askFocused: false,
                askComposing: false,
                askAnswer: '',
                askSources: [],
                askBusy: false,
                askError: '',
                askStatus: '',
                askQuestions: [
                    'What did Henry research?',
                    'What was his time at HSBC like?',
                    'What does he do for fun?',
                    'Where has he travelled?',
                ],
                askQIndex: 0,
                askRotate: null,
            };
        },
        computed: {
            // Idle: cycle through real example questions in a separate overlay so
            // each change can fade instead of snapping like a native placeholder.
            askPromptText() {
                if (this.askFocused) return 'Ask anything about Henry…';
                return this.askQuestions[this.askQIndex];
            },
            showExamplePrompt() {
                return !this.askFocused && !this.askText;
            },
            askAnswerText() {
                return stripAnswerCitations(this.askAnswer);
            },
            homeCitedSources() {
                return citedSourcesFromAnswer(this.askAnswer, this.askSources);
            },
        },
        async mounted() {
            this._askSeq = 0;
            this._onHomeAskReady = this.startAskRotation;
            window.addEventListener('home-ask-ready', this._onHomeAskReady);
            // Dynamically import the script when the component is mounted
            this.scriptModule = await import('../assets/js/home.js');
            if (this.scriptModule && this.scriptModule.initScript) {
                this.scriptModule.initScript();
            }
        },
        unmounted() {
            // Clean up the script when the component is unmounted
            if (this.scriptModule && this.scriptModule.cleanupScript) {
                this.scriptModule.cleanupScript();
            }
            this.scriptModule = null; // Optionally, clear the reference to the module
            if (this._onHomeAskReady) window.removeEventListener('home-ask-ready', this._onHomeAskReady);
            if (this.askRotate) clearInterval(this.askRotate);
            this._askSeq += 1;
        },
        methods: {
            startAskRotation() {
                if (this.askRotate) return;
                this.askRotate = setInterval(() => {
                    if (!this.askFocused && !this.askText) {
                        this.askQIndex = (this.askQIndex + 1) % this.askQuestions.length;
                    }
                }, 4600);
            },
            focusInput() {
                if (this.$refs.askInput) this.$refs.askInput.focus();
            },
            submitAsk(e) {
                if (this.askComposing || (e && e.isComposing)) return; // let IME commit first
                this.askHome(this.askText.trim());
            },
            async askHome(text) {
                const question = String(text || '').trim();
                if (!question || !askConfigured()) return;
                const seq = ++this._askSeq;
                this.askBusy = true;
                this.askError = '';
                this.askAnswer = '';
                this.askSources = [];

                try {
                    this.askStatus = 'Finding relevant sections…';
                    const contexts = await retrieveAskContexts(question, 12);
                    if (seq !== this._askSeq) return;
                    this.askSources = contexts;
                    this.askStatus = 'Thinking…';
                    const payload = contexts.map(c => ({
                        page: c.page,
                        title: c.title,
                        text: cleanAskContextText(c.body),
                    }));
                    for await (const tok of askStream(question, payload)) {
                        if (seq !== this._askSeq) return;
                        this.askAnswer += tok;
                    }
                } catch (err) {
                    if (seq === this._askSeq) this.askError = 'error';
                    console.error('home ask failed:', err);
                } finally {
                    if (seq === this._askSeq) this.askBusy = false;
                }
            },
            goSource(source) {
                if (!source) return;
                const samePage = this.$route.path === source.route;
                const scroll = () => {
                    if (!source.anchor) {
                        window.scrollTo({ top: 0, behavior: 'smooth' });
                        return;
                    }
                    const el = document.getElementById(source.anchor);
                    if (el) el.scrollIntoView({ behavior: 'smooth', block: 'start' });
                };
                if (samePage) {
                    this.$nextTick(scroll);
                } else {
                    this.$router.push(source.route).then(() => {
                        this.$nextTick(scroll);
                    });
                }
            },
        },
    }
</script>
 
