<script>
  import scrollRevealMixin from '../mixins/scrollRevealMixin';

  export default {
    name: 'AboutTab',
    mixins: [scrollRevealMixin],
    data() {
      return {
        scriptModule: null,
        photoLoaded: false,
      };
    },
    async mounted() {
      // If the photo is already cached, its load event may have fired before the
      // listener attached; reveal the watermark immediately in that case.
      if (this.$refs.photo && this.$refs.photo.complete) {
        this.photoLoaded = true;
      }
      // Dynamically import the script when the component is mounted
      this.scriptModule = await import('../assets/js/about.js');
      if (this.scriptModule && this.scriptModule.initScript) {
        this.scriptModule.initScript();
      }
    },
    unmounted() {
      // Clean up the script when the component is unmounted
      if (this.scriptModule && this.scriptModule.cleanupScript) {
        this.scriptModule.cleanupScript();
      }
      this.scriptModule = null; // Optionally, clear the reference to the module
    },
  }

</script>

